CODE_EXAMPLE:
// Before
Customer newCustomer = new Customer(name);

// After
Customer newCustomer = Customer.create(name);

class Customer {
  private static Map instances = new HashMap();
  static Customer create(String name) {
    if (!instances.containsKey(name)) {
      instances.put(name, new Customer(name));
    }
    return (Customer) instances.get(name);
  }
}

UNIT_TEST_EXAMPLE:
@Test
public void testValueToReference() {
  Customer c1 = Customer.create("John");
  Customer c2 = Customer.create("John");
  assertSame(c1, c2);
}
